final:
module RefModule (  
    input clk,  
    input T,  
    input reset,  
    output reg Q  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            Q <= 0;  
        end else if (T) begin  
            Q <= ~Q;  
        end  
    end  
endmodule
